export const SAMPLE_PUZZLES: Puzzle[] = RAW_PUZZLES.map(p => ({
  ...p,
  difficulty: rateDifficulty(p as Puzzle),
}));

export function getPuzzleById(id: string): Puzzle | undefined {
  return SAMPLE_PUZZLES.find(p => p.id === id);
}
